const money = n => new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(Number(n || 0));
const localDate = date => `${date.getFullYear()}-${String(date.getMonth()+1).padStart(2,'0')}-${String(date.getDate()).padStart(2,'0')}`;
const today = () => localDate(new Date());
const addDays = days => { const d = new Date(); d.setDate(d.getDate() + days); return localDate(d); };
const reportPeriod = scope => { const now=new Date(),end=today(); if(scope==='all')return {from:'',to:''}; if(scope==='month')return {from:`${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}-01`,to:end}; return {from:`${now.getFullYear()}-01-01`,to:end}; };
const setNativeInputValue=(input,value)=>{const setter=Object.getOwnPropertyDescriptor(HTMLInputElement.prototype,'value')?.set;setter?.call(input,value);input.dispatchEvent(new Event('input',{bubbles:true}));input.dispatchEvent(new Event('change',{bubbles:true}))};
const reportFileName=title=>`${String(title||'report').toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'')}-${today()}`;
const readReportExport=title=>{const page=document.querySelector('.reports-page'),summary=[...(page?.querySelectorAll('.statement-summary > div')||[])].map(item=>[item.querySelector('small')?.textContent?.trim()||'',item.querySelector('strong')?.textContent?.trim()||'',item.querySelector('span')?.textContent?.trim()||'']),tables=[...(page?.querySelectorAll('.report-table')||[])].map(table=>({title:table.querySelector('h3')?.textContent?.trim()||'Report detail',rows:[...(table.querySelectorAll('.report-row')||[])].map(row=>[...row.querySelectorAll(':scope > span')].map(cell=>cell.textContent.trim()))}));return {title,summary,tables}};
const csvValue=value=>`"${String(value??'').replaceAll('"','""')}"`;
function exportReportCsv(title){const report=readReportExport(title),rows=[[report.title],['Generated',new Date().toLocaleString()],...report.summary,...report.tables.flatMap(table=>[[],[table.title],...table.rows])],blob=new Blob([rows.map(row=>row.map(csvValue).join(',')).join('\r\n')],{type:'text/csv;charset=utf-8'}),url=URL.createObjectURL(blob),link=document.createElement('a');link.href=url;link.download=`${reportFileName(title)}.csv`;link.click();URL.revokeObjectURL(url)}
async function exportReportPdf(title){const {jsPDF}=await import('jspdf'),report=readReportExport(title),doc=new jsPDF({unit:'pt',format:'letter'}),left=46,width=520,bottom=742;let y=50;const line=text=>{for(const part of doc.splitTextToSize(String(text),width)){if(y>bottom){doc.addPage();y=50}doc.text(part,left,y);y+=15}};doc.setFont('helvetica','bold');doc.setFontSize(18);line(report.title);doc.setFont('helvetica','normal');doc.setFontSize(9);line(`Generated ${new Date().toLocaleString()}`);y+=8;for(const row of report.summary)line(row.filter(Boolean).join('  |  '));for(const table of report.tables){y+=12;doc.setFont('helvetica','bold');doc.setFontSize(11);line(table.title);doc.setFont('helvetica','normal');doc.setFontSize(8);for(const row of table.rows)line(row.join('  |  '))}doc.save(`${reportFileName(title)}.pdf`)}
function ReportToolbar({title,section}){const [scope,setScope]=useState('ytd'),[custom,setCustom]=useState(reportPeriod('ytd'));const apply=(next,override)=>{const dates=override||(next==='custom'?custom:reportPeriod(next)),inputs=[...document.querySelectorAll('.reports-page input[type="date"]')];inputs.forEach((input,index)=>setNativeInputValue(input,index%2===0?dates.from:dates.to))};useEffect(()=>{setScope('ytd');const dates=reportPeriod('ytd');setCustom(dates);requestAnimationFrame(()=>apply('ytd',dates))},[section]);return <section className="panel report-toolbar"><div><small>Report period</small><select value={scope} onChange={event=>{const next=event.target.value;setScope(next);apply(next)}}><option value="ytd">Year to date</option><option value="month">Current month</option><option value="all">All time</option><option value="custom">Custom range</option></select>{scope==='custom'&&<span className="report-custom-range"><input type="date" value={custom.from} max={custom.to||undefined} onChange={event=>{const next={...custom,from:event.target.value};setCustom(next);apply('custom',next)}}/><span>to</span><input type="date" value={custom.to} min={custom.from||undefined} onChange={event=>{const next={...custom,to:event.target.value};setCustom(next);apply('custom',next)}}/></span>}</div><div><button type="button" className="quiet" onClick={()=>exportReportCsv(title)}>Export CSV</button><button type="button" className="primary" onClick={()=>exportReportPdf(title)}>Export PDF</button></div></section>}
async function exportInvoicePdf(invoice,client,payments=[]) {
  const {jsPDF}=await import('jspdf');
  const doc=new jsPDF({unit:'pt',format:'letter'}),left=52,right=560,pageBottom=735,items=invoice.items||[],paid=Number(invoice.paid||0),balance=Math.max(0,Number(invoice.amount||0)-paid);
  const header=()=>{doc.setFillColor(55,71,76);doc.rect(0,0,612,72,'F');doc.setTextColor(53,169,213);doc.setFont('helvetica','bold');doc.setFontSize(18);doc.text('KINDRED INNOVIA',left,34);doc.setTextColor(220,237,243);doc.setFontSize(8);doc.setFont('helvetica','normal');doc.text('CAREFUL TECHNOLOGY',left,49);doc.setFontSize(26);doc.setFont('helvetica','bold');doc.text('INVOICE',right,39,{align:'right'});doc.setFontSize(10);doc.setFont('helvetica','normal');doc.text(invoice.id,right,55,{align:'right'});doc.setTextColor(23,43,61)};
  const newPage=()=>{doc.addPage();header();return 104};
  header();let y=108;doc.setFontSize(8);doc.setTextColor(8,133,182);doc.setFont('helvetica','bold');doc.text('BILL TO',left,y);doc.text('INVOICE DETAILS',355,y);doc.setTextColor(23,43,61);doc.setFontSize(13);doc.text(client?.name||'Client',left,y+20);doc.setFont('helvetica','normal');doc.setFontSize(10);if(client?.address)doc.text(client.address,left,y+37);doc.text([client?.city,client?.state,client?.zip].filter(Boolean).join(', ').replace(', '+(client?.zip||''),' '+(client?.zip||'')),left,y+(client?.address?52:37));doc.text(`Issued: ${invoice.issued}`,355,y+20);doc.text(`Due: ${invoice.due}`,355,y+37);doc.text(`Status: ${String(invoice.status||'').replaceAll('_',' ')}`,355,y+54);
  y=190;doc.setFillColor(221,239,247);doc.rect(left,y,right-left,26,'F');doc.setFont('helvetica','bold');doc.setFontSize(8);doc.text('DESCRIPTION',left+9,y+17);doc.text('QTY',390,y+17,{align:'right'});doc.text('RATE',475,y+17,{align:'right'});doc.text('TOTAL',right-8,y+17,{align:'right'});y+=36;
  doc.setFont('helvetica','normal');doc.setFontSize(10);
  for(const item of items){const description=doc.splitTextToSize(String(item.description||''),275),height=Math.max(30,description.length*12+12);if(y+height>pageBottom)y=newPage();doc.text(description,left+9,y+10);doc.text(String(item.quantity),390,y+10,{align:'right'});doc.text(money(item.rate),475,y+10,{align:'right'});doc.setFont('helvetica','bold');doc.text(money(Number(item.quantity)*Number(item.rate)),right-8,y+10,{align:'right'});doc.setFont('helvetica','normal');doc.setDrawColor(215,226,232);doc.line(left,y+height-5,right,y+height-5);y+=height;}
  if(y+126>pageBottom)y=newPage();y+=12;const valueX=right-8,labelX=430;doc.setFontSize(10);doc.text('Subtotal',labelX,y);doc.text(money(invoice.amount),valueX,y,{align:'right'});y+=19;doc.text('Payments',labelX,y);doc.text(`-${money(paid)}`,valueX,y,{align:'right'});y+=24;doc.setFillColor(8,43,59);doc.rect(410,y-16,150,34,'F');doc.setTextColor(255,255,255);doc.setFont('helvetica','bold');doc.text('BALANCE',422,y+5);doc.setFontSize(13);doc.text(money(balance),valueX,y+5,{align:'right'});doc.setTextColor(23,43,61);y+=55;
  if(payments.length){if(y+45>pageBottom)y=newPage();doc.setFontSize(8);doc.setTextColor(8,133,182);doc.text('PAYMENT HISTORY',left,y);doc.setTextColor(23,43,61);doc.setFont('helvetica','normal');doc.setFontSize(9);y+=17;for(const payment of payments){if(y>pageBottom)y=newPage();doc.text(`${payment.date}  |  ${String(payment.method).replaceAll('_',' ')}`,left,y);doc.text(money(payment.amount),right,y,{align:'right'});y+=17;}}
  doc.setFontSize(8);doc.setTextColor(100,125,138);doc.text('Thank you for your business.',left,760);doc.text(`Invoice ${invoice.id}`,right,760,{align:'right'});doc.save(`${invoice.id}.pdf`);
}
