  const applyRoute=(route,workspace=data)=>{setPage(route.page);setModal(null);setInvoiceScreen(null);setClientScreen(null);setTicketScreen(null);if(route.page==='Reports'){setReportSection(reportSections.some(item=>item.slug===route.id)?route.id:'revenue-by-client');return}if(!workspace||!route.id)return;if(route.page==='Invoices'){const record=workspace.invoices.find(item=>String(item.id)===route.id);if(record)setInvoiceScreen({mode:'preview',documentType:'invoice',invoice:record})}else if(route.page==='Clients'){const record=workspace.clients.find(item=>String(item.id)===route.id);if(record)setClientScreen(record)}else if(route.page==='Tickets'){const record=(workspace.tickets||[]).find(item=>String(item.id)===route.id);if(record)setTicketScreen(record)}};
