    {(invoiceScreen||modal==='invoice'||modal==='estimate')&&<InvoiceScreen documentType={invoiceScreen?.documentType||(modal==='estimate'?'estimate':'invoice')} mode={invoiceScreen?.mode||'create'} invoice={invoiceScreen?.invoice} defaultClientId={invoiceScreen?.clientId} data={data} refresh={load} onDirty={setUnsaved} close={()=>{setUnsaved(false);setInvoiceScreen(null);setModal(null)}} reload={async(id,documentType)=>{const next=await load();setUnsaved(false);setModal(null);if(documentType==='invoice'){const saved=next.invoices.find(item=>item.id===id);setInvoiceScreen(saved?{mode:'preview',documentType:'invoice',invoice:saved}:null)}else setInvoiceScreen(null)}} recordPayment={invoiceId=>setModal({type:'payment',invoiceId})} openClient={selected=>{setUnsaved(false);setModal(null);openClient(selected)}}/>}
    {clientScreen&&<ClientScreen client={data.clients.find(item=>item.id===clientScreen.id)||clientScreen} data={data} refresh={load} close={()=>setClientScreen(null)} openInvoice={openInvoice} createInvoice={()=>{setClientScreen(null);setPage('Invoices');setInvoiceScreen({mode:'create',clientId:clientScreen.id})}} createTicket={()=>{setClientScreen(null);setPage('Tickets');setModal({type:'ticket',clientId:clientScreen.id})}} createQuote={()=>{setClientScreen(null);setPage('Estimates');setInvoiceScreen({mode:'create',documentType:'estimate',clientId:clientScreen.id})}}/>}
    {ticketScreen&&<TicketScreen ticket={ticketScreen} data={data} close={()=>setTicketScreen(null)} refresh={load} navigate={navigate} openClient={openClient} createExpense={()=>setModal({type:'expense',clientId:ticketScreen.clientId,ticketId:ticketScreen.id})}/>}
    {ticketScreen&&<TicketExpenseDock ticket={ticketScreen} data={data} create={()=>setModal({type:'expense',clientId:ticketScreen.clientId,ticketId:ticketScreen.id})}/>}
